/* This does NOT work: a and b are copies */
void bad_swap(int a, int b) {
    int temp = a;
    a = b;
    b = temp;
    /* only local copies are swapped */
}

/* This works: pointers to originals */
void good_swap(int *a, int *b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

/* Demonstrating that the pointer itself is a copy */
void try_change_ptr(int *p) {
    int local = 99;
    p = &local;  /* only changes the local copy of the pointer */
}

int main(void) {
    int x = 10, y = 20;

    bad_swap(x, y);
    printf("After bad_swap:  x=%d y=%d\n", x, y);  /* x=10 y=20 */

    good_swap(&x, &y);
    printf("After good_swap: x=%d y=%d\n", x, y);  /* x=20 y=10 */

    /* Pointer itself is passed by value */
    int val = 42;
    int *ptr = &val;
    try_change_ptr(ptr);
    printf("ptr still points to: %d\n", *ptr); /* 42, not 99 */

    return 0;
}

