#include <stdio.h>

/* Non-tail recursive: multiplication after recursive call */
int factorial(int n) {
    if (n <= 1) return 1;
    return n * factorial(n - 1);  /* n * ... is done AFTER call returns */
}

/* Tail recursive: call is the last operation */
int factorial_tail(int n, int acc) {
    if (n <= 1) return acc;
    return factorial_tail(n - 1, n * acc); /* nothing after this call */
}

/* Wrapper for clean API */
int factorial_optimized(int n) {
    return factorial_tail(n, 1);
}

/* Tail recursive GCD (naturally tail recursive) */
int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);  /* last operation is the call */
}

int main(void) {
    printf("5! = %d\n", factorial(5));           /* 120 */
    printf("5! = %d\n", factorial_optimized(5));  /* 120 */
    printf("gcd(48,18) = %d\n", gcd(48, 18));    /* 6 */
    return 0;
}

