    return 0;
}

#include <stdio.h>

/* Recursive: natural for the problem */
int sum_recursive(int n) {
    if (n <= 0) return 0;
    return n + sum_recursive(n - 1);
}

/* Iterative: more efficient for this simple case */
int sum_iterative(int n) {
    int total = 0;
    for (int i = 1; i <= n; i++) {
        total += i;
    }
    return total;
}

/* Recursive: natural for binary search */
int bsearch_recursive(int arr[], int lo, int hi, int target) {
    if (lo > hi) return -1;
    int mid = lo + (hi - lo) / 2;
    if (arr[mid] == target) return mid;
    if (arr[mid] < target) return bsearch_recursive(arr, mid + 1, hi, target);
    return bsearch_recursive(arr, lo, mid - 1, target);
}

/* Iterative: safer for large arrays */
int bsearch_iterative(int arr[], int n, int target) {
    int lo = 0, hi = n - 1;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (arr[mid] == target) return mid;
        if (arr[mid] < target) lo = mid + 1;
        else hi = mid - 1;
    }
    return -1;
}

int main(void) {
    printf("sum(100) recursive: %d\n", sum_recursive(100));  /* 5050 */
    printf("sum(100) iterative: %d\n", sum_iterative(100));  /* 5050 */

    int arr[] = {1, 3, 5, 7, 9, 11, 13};
    printf("find 7: idx %d\n", bsearch_recursive(arr, 0, 6, 7));  /* 3 */
    printf("find 7: idx %d\n", bsearch_iterative(arr, 7, 7));     /* 3 */

    return 0;
}

