#include <stdio.h>
#include <stdlib.h>

/* This WILL stack overflow for large n */
int sum_recursive(int n) {
    if (n <= 0) return 0;
    return n + sum_recursive(n - 1);
}

/* Safe iterative version */
long sum_iterative(int n) {
    long total = 0;
    for (int i = 1; i <= n; i++) {
        total += i;
    }
    return total;
}

/* Simulating recursion with explicit stack */
long sum_with_stack(int n) {
    int *stack = malloc(n * sizeof(int));
    if (!stack) return -1;

    int top = 0;
    for (int i = n; i > 0; i--) {
        stack[top++] = i;
    }

    long total = 0;
    while (top > 0) {
        total += stack[--top];
    }

    free(stack);
    return total;
}

int main(void) {
    /* Safe for small n */
    printf("sum(100) = %d\n", sum_recursive(100)); /* 5050 */

    /* Iterative works for any n */
    printf("sum(1000000) = %ld\n", sum_iterative(1000000));

    /* Explicit stack also works for any n */
    printf("sum(1000000) = %ld\n", sum_with_stack(1000000));

    /* DO NOT: sum_recursive(1000000) -- stack overflow! */
    return 0;
}

