#include <stdio.h>
#include <stdlib.h>

/* Functions with matching signatures */
int add(int a, int b) { return a + b; }
int sub(int a, int b) { return a - b; }
int mul(int a, int b) { return a * b; }

/* Higher-order function using callback */
int apply(int (*op)(int, int), int a, int b) {
    return op(a, b);
}

/* qsort comparison callback */
int compare_int(const void *a, const void *b) {
    return (*(const int *)a - *(const int *)b);
}

int main(void) {
    /* Basic function pointer */
    int (*fp)(int, int) = add;
    printf("fp(3, 4) = %d\n", fp(3, 4)); /* 7 */

    fp = mul;
    printf("fp(3, 4) = %d\n", fp(3, 4)); /* 12 */

    /* Callback pattern */
    printf("add: %d\n", apply(add, 10, 3));  /* 13 */
    printf("sub: %d\n", apply(sub, 10, 3));  /* 7 */
    printf("mul: %d\n", apply(mul, 10, 3));  /* 30 */

    /* Dispatch table */
    int (*ops[])(int, int) = {add, sub, mul};
    const char *names[] = {"+", "-", "*"};
    for (int i = 0; i < 3; i++) {
        printf("5 %s 3 = %d\n", names[i], ops[i](5, 3));
    }

    /* qsort with callback */
    int arr[] = {5, 2, 8, 1, 9, 3};
    qsort(arr, 6, sizeof(int), compare_int);
    for (int i = 0; i < 6; i++) printf("%d ", arr[i]);
    printf("\n"); /* 1 2 3 5 8 9 */

    return 0;
}

