#include <stdlib.h>

void cleanup(void) {
    printf("Cleanup called\n");
}

int main(int argc, char *argv[]) {
    /* Register cleanup function */
    atexit(cleanup);

    if (argc < 2) {
        fprintf(stderr, "Error: missing argument\n");
        return EXIT_FAILURE; /* non-zero = error */
        /* Shell: echo $? prints 1 */
    }

    printf("Processing: %s\n", argv[1]);

    /* exit() can be called from anywhere */
    if (argv[1][0] == 'q') {
        printf("Quitting early\n");
        exit(EXIT_SUCCESS); /* calls atexit handlers */
    }

    printf("Done\n");
    return EXIT_SUCCESS; /* 0 = success */
    /* Shell: echo $? prints 0 */

    /* Cleanup called in both cases (atexit) */
}

